		item := heap.Pop(&pq).(*Item)
		cost := item.cost
		node := item.node
		state := item.state

		if state == 0 && d0[node] != cost {
			continue
		}
		if state == 1 && d1[node] != cost {
			continue
		}

		if state == 0 {
